queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?suitetype WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSuites ?child ; p:hasGuestHouses ?parent . } GROUP BY ?child }
  ?child p:suiteType ?suitetype .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :GuestHouses } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?housename ?suitetype WHERE {
  ?guesthousesuites a :GuestHouseSuites .
  ?suites a :Suites .
  ?guesthousesuites p:hasSuites ?suites .
  ?guesthouses a :GuestHouses .
  ?guesthousesuites p:hasGuestHouses ?guesthouses .
  ?guesthouses p:houseName ?housename .
  ?suites p:suiteType ?suitetype .
} }
  collective: { SELECT ?suitetype WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSuites ?child ; p:hasGuestHouses ?parent . } GROUP BY ?child }
  ?child p:suiteType ?suitetype .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :GuestHouses } }
  FILTER(?nf = ?total)
} }
}
